import { GoogleGenAI, Type } from "@google/genai";
import { AppEvent } from '../types.ts';

// Helper to get a formatted error message
const getFormattedError = (err: unknown): string => {
    if (err instanceof Error) return err.message;
    if (typeof err === 'string') return err;
    if (err && typeof err === 'object' && 'message' in err && typeof (err as any).message === 'string') {
        const apiError = err as { message: string; details?: string; hint?: string; code?: string };
        return `API Error: ${apiError.message}${apiError.details ? ` Details: ${apiError.details}` : ''}`;
    }
    try {
        return `An unexpected error occurred: ${JSON.stringify(err)}`;
    } catch {
        return 'An unknown and un-serializable error occurred.';
    }
};

// Initialize the Gemini API client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Generates a marketing description for a tourism cluster.
 * Uses Gemini 3 Flash for high-speed, cost-effective creative writing.
 */
export const generateClusterDescription = async (name: string, categories: string[], vibe: string): Promise<string> => {
    try {
        const prompt = `As a creative tourism copywriter, write a short, engaging marketing description for a tourism spot in Sarawak, Malaysia named "${name}" which falls under the categories "${categories.join(', ')}". ${vibe ? `The desired tone is "${vibe}". Craft the description in a compelling, ${vibe} style.` : ''} Highlight its key attractions in 2-3 concise sentences.`;

        const response = await ai.models.generateContent({ 
            model: 'gemini-3-flash-preview', 
            contents: prompt 
        });

        return response.text.trim();
    } catch (error) {
        throw new Error(getFormattedError(error));
    }
};

/**
 * Generates an analytical summary for events in a given year.
 * Uses Gemini 3 Pro with Google Search for high-accuracy analytical reporting.
 */
type GroundingChunk = { web?: { uri?: string; title?: string } };
export const generateEventAnalyticsInsight = async (events: AppEvent[], year: number): Promise<{ summary: string; sources: GroundingChunk[] }> => {
    if (events.length === 0) {
        return { summary: "No event data for this year to analyze.", sources: [] };
    }

    try {
        const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
        const monthlyData = monthNames.map(name => ({ month: name, 'Number of Events': 0 }));
        events.forEach(event => {
            const monthIndex = new Date(event.start_date).getMonth();
            monthlyData[monthIndex]['Number of Events']++;
        });

        const eventTitles = events.map(e => e.title).slice(0, 100).join(', ');
        const monthlyCounts = monthlyData.map(m => `${m.month}: ${m['Number of Events']}`).join(', ');

        const prompt = `
            As a professional data analyst preparing a report for the Sarawak Tourism Board, your task is to analyze the provided event data for Sarawak in the year ${year}. Use web search to verify the cultural significance of the listed events.

            Data:
            - Titles: ${eventTitles}.
            - Distribution: ${monthlyCounts}.

            Report Structure:
            1. Total events and peak/off-peak analysis.
            2. Recurring themes (Cultural, Adventure, etc.).
            3. Contextual details from web search about major festivals.
            4. Predictive outlook for next year based on trends.
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: prompt,
            config: {
                tools: [{ googleSearch: {} }],
            },
        });

        const summary = response.text;
        const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

        return { summary, sources };
    } catch (error) {
        console.error("Error in generateEventAnalyticsInsight:", getFormattedError(error));
        return { summary: "Could not generate AI-powered insights. Ensure your API key has Google Search enabled.", sources: [] };
    }
};

/**
 * Generates trip recommendations based on user preferences and available items.
 * Uses Gemini 3 Pro for advanced reasoning and constraint matching.
 */
interface Recommendation {
    id: string;
    type: 'cluster' | 'event';
    name: string;
    justification: string;
    location: string;
}
export const generateItineraryRecommendations = async (preferences: any, items: any[]): Promise<Recommendation[]> => {
    try {
        const dataForAI = items.map(item => {
            if (item.itemType === 'cluster') {
                return { id: item.id, name: item.name, location: item.display_address || item.location, category: item.category.join(', ') };
            } else { // 'event'
                return { id: item.id, name: item.title, location: item.display_address || item.location_name, category: item.category };
            }
        });

        const prompt = `
            You are an expert travel planner for Sarawak. Recommend exactly 5 items from the dataset that best fit:
            - Location: ${preferences.location || 'Anywhere'}
            - Interests: ${Array.from(preferences.activities).join(', ')}
            - Duration: ${preferences.duration} days
            - Budget: RM ${preferences.budget}

            Dataset: ${JSON.stringify(dataForAI)}
        `;

        const responseSchema = {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    id: { type: Type.STRING },
                    type: { type: Type.STRING },
                    name: { type: Type.STRING },
                    location: { type: Type.STRING },
                    justification: { type: Type.STRING }
                },
                required: ["id", "type", "name", "location", "justification"]
            }
        };

        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: responseSchema,
            },
        });

        return JSON.parse(response.text);
    } catch (error) {
        console.error(`AI Itinerary Generation Failed`, error);
        throw new Error(`AI generation failed: ${getFormattedError(error)}`);
    }
};

import React, { useState, useMemo, useEffect } from 'react';
import { ViewName, ItineraryItem, Cluster } from '../../types.ts';
import { useAppContext } from '../AppContext.tsx';
import Card from '../ui/Card.tsx';
import Button from '../ui/Button.tsx';
import Input from '../ui/Input.tsx';
import Spinner from '../ui/Spinner.tsx';
import { SparklesIcon, TourismClusterIcon, EventsCalendarIcon, PlusIcon, MapPinIcon, TrashIcon, QuestionMarkCircleIcon } from '../../constants.tsx';
import { generateItineraryRecommendations } from '../../services/gemini.ts';
import ClusterDetailModal from '../ui/ClusterDetailModal.tsx';
import InteractiveGuide from '../ui/InteractiveGuide.tsx';

interface AIPlannerViewProps {
  setCurrentView: (view: ViewName) => void;
  onAuthRequired?: (message?: string) => void;
}

interface Recommendation {
    id: string;
    type: 'cluster' | 'event';
    name: string;
    justification: string;
    location: string;
}

const activityOptions = ['Nature', 'Culture', 'Adventure', 'Food', 'Festivals', 'History', 'Relaxation'];

const MyItinerary: React.FC = () => {
    const { myItinerary, isLoadingItinerary, removeItineraryItem, clearMyItinerary } = useAppContext();
    const [clearingItemId, setClearingItemId] = useState<string | null>(null);

    const handleRemove = async (item: ItineraryItem) => {
        setClearingItemId(item.id);
        await removeItineraryItem(item.id);
        setClearingItemId(null);
    };

    return (
        <Card id="my-itinerary-card" title="My Itinerary">
            {isLoadingItinerary ? (
                <div className="text-center py-8"><Spinner /></div>
            ) : myItinerary.length === 0 ? (
                <p className="text-center text-sm text-brand-text-secondary-light dark:text-brand-text-secondary py-8">
                    Your itinerary is empty. Get recommendations and add them here!
                </p>
            ) : (
                <div className="space-y-3 max-h-96 overflow-y-auto custom-scrollbar pr-2">
                    {myItinerary.map(item => (
                        <div key={item.id} className="p-3 rounded-md bg-neutral-100-light dark:bg-neutral-800-dark flex items-center justify-between gap-4">
                            <div className="flex items-center gap-3 overflow-hidden">
                                {item.item_type === 'cluster' 
                                    ? <TourismClusterIcon className="w-6 h-6 text-brand-green dark:text-brand-dark-green-text flex-shrink-0" />
                                    : <EventsCalendarIcon className="w-6 h-6 text-brand-green dark:text-brand-dark-green-text flex-shrink-0" />
                                }
                                <div className="truncate">
                                    <p className="font-semibold text-brand-text-light dark:text-brand-text truncate" title={item.item_name}>{item.item_name}</p>
                                    <p className="text-xs text-brand-text-secondary-light dark:text-brand-text-secondary capitalize">{item.item_type}</p>
                                </div>
                            </div>
                            <Button 
                                variant="ghost" 
                                size="sm" 
                                className="text-red-500 hover:bg-red-500/10 flex-shrink-0" 
                                onClick={() => handleRemove(item)}
                                isLoading={clearingItemId === item.id}
                                aria-label={`Remove ${item.item_name}`}
                            >
                                <TrashIcon className="w-4 h-4" />
                            </Button>
                        </div>
                    ))}
                </div>
            )}
             {myItinerary.length > 0 && (
                <div className="mt-4 pt-4 border-t border-neutral-200-light dark:border-neutral-700-dark text-right">
                    <Button variant="secondary" size="sm" onClick={clearMyItinerary}>
                        Clear All Items
                    </Button>
                </div>
            )}
        </Card>
    );
};

const aiPlannerTourSteps = [
    { selector: '#ai-planner-form', title: 'Set Your Preferences', content: 'Fill in your desired location, trip duration, budget, and select your interests. The more details you provide, the better the recommendations will be.' },
    { selector: '#get-recommendations-btn', title: 'Get Recommendations', content: 'Once your preferences are set, click this button. Our AI will analyze your input and generate a personalized list of suggestions for your trip.' },
    { selector: '#ai-recommendations-list', title: 'Your Recommendations', content: 'The AI-generated recommendations will appear here. Each one includes a justification explaining why it\'s a good fit for you. You can view details or add items to your personal itinerary.' },
    { selector: '#my-itinerary-card', title: 'My Itinerary', content: 'Items you add will appear here. This list is saved to your account, so you can come back and view your planned trip at any time.' },
];

const AIPlannerView: React.FC<AIPlannerViewProps> = ({ setCurrentView, onAuthRequired }) => {
    const { clusters, events, currentUser, addItineraryItem } = useAppContext();

    const [preferences, setPreferences] = useState({
        location: '',
        activities: new Set<string>(),
        duration: 3,
        budget: 500,
    });
    const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [addingItemId, setAddingItemId] = useState<string | null>(null);
    const [viewingCluster, setViewingCluster] = useState<Cluster | null>(null);
    const [isGuideActive, setIsGuideActive] = useState(false);

    useEffect(() => {
        const guideToStart = sessionStorage.getItem('startGuideFor');
        if (guideToStart === ViewName.AIPlanner) {
            setIsGuideActive(true);
            sessionStorage.removeItem('startGuideFor');
        }
    }, []);

    useEffect(() => {
        try {
            const savedStateJSON = sessionStorage.getItem('aiPlannerState');
            if (savedStateJSON) {
                sessionStorage.removeItem('aiPlannerState'); // Clear it immediately
                const savedState = JSON.parse(savedStateJSON);

                if (savedState.preferences) {
                    // Convert activities array back to a Set
                    savedState.preferences.activities = new Set(savedState.preferences.activities || []);
                    setPreferences(savedState.preferences);
                }
                if (savedState.recommendations) {
                    setRecommendations(savedState.recommendations);
                }
                if (savedState.error) {
                    setError(savedState.error);
                }
            }
        } catch (e) {
            console.error("Failed to restore AI Planner state from session storage", e);
            sessionStorage.removeItem('aiPlannerState');
        }
    }, []); // Empty dependency array ensures it runs only on mount.

    const handleActivityToggle = (activity: string) => {
        setPreferences(prev => {
            const newActivities = new Set(prev.activities);
            if (newActivities.has(activity)) {
                newActivities.delete(activity);
            } else {
                newActivities.add(activity);
            }
            return { ...prev, activities: newActivities };
        });
    };

    const handleGetRecommendations = async () => {
        setIsLoading(true);
        setError(null);
        setRecommendations([]);

        try {
            const locationLower = preferences.location.toLowerCase();
            // FIX: Robustly convert each activity to string before calling toLowerCase to avoid "Property 'toLowerCase' does not exist on type 'unknown'" error.
            const selectedActivities = Array.from(preferences.activities).map(a => String(a).toLowerCase());

            const relevantClusters = clusters.filter(c => {
                const matchesLocation = !locationLower || (c.display_address || c.location).toLowerCase().includes(locationLower);
                // FIX: The type of `cat` within the `some` callback was being inferred as `unknown`,
                // causing an error on `cat.toLowerCase()`. Using `String(cat)` is a robust way to handle
                // potential non-string values and resolve the type error.
                const matchesActivity = selectedActivities.length === 0 || c.category.some(cat => selectedActivities.includes(String(cat).toLowerCase()));
                return matchesLocation && matchesActivity;
            });

            const relevantEvents = events.filter(e => {
                const matchesLocation = !locationLower || (e.display_address || e.location_name).toLowerCase().includes(locationLower);
                const matchesActivity = selectedActivities.length === 0 || selectedActivities.includes(e.category.toLowerCase());
                return matchesLocation && matchesActivity;
            });

            if (relevantClusters.length === 0 && relevantEvents.length === 0) {
                 setError("We couldn't find any locations or events matching your search criteria. Please try a broader location like 'Kuching' or 'Miri'.");
                 setIsLoading(false);
                 return;
            }

            const allRelevantItems = [
                ...relevantClusters.map(c => ({ ...c, itemType: 'cluster' as const })),
                ...relevantEvents.map(e => ({ ...e, itemType: 'event' as const }))
            ];
            const shuffledItems = allRelevantItems.sort(() => 0.5 - Math.random());
            const selectedItems = shuffledItems.slice(0, 30);

            const result = await generateItineraryRecommendations(preferences, selectedItems);
            setRecommendations(result);

        } catch (err) {
            console.error("AI Planner Error:", err);
            const errorMessage = err instanceof Error ? err.message : "Sorry, we couldn't generate recommendations at this time. Please try adjusting your preferences or try again later.";
            setError(`AI generation failed: ${errorMessage}`);
        } finally {
            setIsLoading(false);
        }
    };

    const handleViewDetails = (item: Recommendation) => {
        if (item.type === 'cluster') {
            const fullCluster = clusters.find(c => c.id === item.id);
            if (fullCluster) {
                setViewingCluster(fullCluster);
            } else {
                // Fallback for safety if cluster data somehow isn't available
                sessionStorage.setItem('initialClusterSearch', item.name);
                setCurrentView(ViewName.TourismCluster);
            }
        } else {
            sessionStorage.setItem('initialEventSearch', item.name);
            setCurrentView(ViewName.EventsCalendar);
        }
    };

    const handleAddToItinerary = async (item: Recommendation) => {
        if (!currentUser) {
            // Save state before prompting login
            const stateToSave = {
                preferences: {
                    ...preferences,
                    activities: Array.from(preferences.activities), // Convert Set to Array for JSON
                },
                recommendations,
                error,
            };
            sessionStorage.setItem('aiPlannerState', JSON.stringify(stateToSave));
            onAuthRequired?.("Please log in or register to save items to your itinerary.");
            return;
        }
        setAddingItemId(item.id);
        await addItineraryItem(item.id, item.type, item.name);
        setAddingItemId(null);
    };

    return (
        <>
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 items-start">
            <div className="lg:col-span-2 space-y-6">
                <Card title={
                    <div className="flex items-center gap-3">
                        <span>AI Trip Planner</span>
                        <button onClick={() => setIsGuideActive(true)} title="Start Interactive Guide for this page" className="text-brand-text-secondary-light dark:text-brand-text-secondary hover:text-brand-green-text dark:hover:text-brand-dark-green-text">
                            <QuestionMarkCircleIcon className="w-6 h-6" />
                        </button>
                    </div>
                } titleIcon={<SparklesIcon className="w-6 h-6" />}>
                    <div id="ai-planner-form" className="space-y-4">
                        <p className="text-brand-text-secondary-light dark:text-brand-text-secondary">
                            Tell us about your ideal trip, and our AI will craft personalized recommendations for you.
                        </p>
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                            <Input
                                label="Location"
                                placeholder="e.g., Kuching, Miri"
                                value={preferences.location}
                                onChange={e => setPreferences(p => ({ ...p, location: e.target.value }))}
                            />
                            <Input
                                label="Trip Duration (days)"
                                type="number"
                                min="1"
                                value={String(preferences.duration)}
                                onChange={e => setPreferences(p => ({ ...p, duration: parseInt(e.target.value, 10) || 1 }))}
                            />
                            <Input
                                label="Budget per person (RM)"
                                type="number"
                                min="0"
                                step="50"
                                value={String(preferences.budget)}
                                onChange={e => setPreferences(p => ({ ...p, budget: parseInt(e.target.value, 10) || 0 }))}
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-brand-text-secondary-light dark:text-brand-text-secondary mb-2">Interests</label>
                            <div className="flex flex-wrap gap-2">
                                {activityOptions.map(activity => (
                                    <button
                                        key={activity}
                                        onClick={() => handleActivityToggle(activity)}
                                        className={`px-3 py-1.5 text-sm rounded-full transition-colors ${
                                            preferences.activities.has(activity)
                                                ? 'bg-brand-green dark:bg-brand-dark-green text-white font-semibold'
                                                : 'bg-neutral-200-light dark:bg-neutral-700-dark hover:bg-neutral-300-light dark:hover:bg-neutral-600-dark'
                                        }`}
                                    >
                                        {activity}
                                    </button>
                                ))}
                            </div>
                        </div>
                        <div id="get-recommendations-btn" className="flex justify-end pt-4">
                            <Button
                                variant="primary"
                                size="lg"
                                onClick={handleGetRecommendations}
                                isLoading={isLoading}
                                leftIcon={<SparklesIcon className="w-5 h-5" />}
                            >
                                Get Recommendations
                            </Button>
                        </div>
                    </div>
                </Card>

                {isLoading && (
                    <div className="text-center py-12">
                        <Spinner className="w-12 h-12 mx-auto" />
                        <p className="mt-4 text-lg font-semibold text-brand-text-light dark:text-brand-text">
                            Our AI is crafting your personalized trip...
                        </p>
                        <p className="text-brand-text-secondary-light dark:text-brand-text-secondary">This may take a moment.</p>
                    </div>
                )}

                {error && (
                    <Card>
                        <p className="text-center text-red-500 dark:text-red-400 py-8">{error}</p>
                    </Card>
                )}

                {recommendations.length > 0 && (
                    <div id="ai-recommendations-list" className="space-y-6">
                        <h2 className="text-2xl font-semibold text-brand-text-light dark:text-brand-text">Your Personalized Recommendations</h2>
                        {recommendations.map((rec, index) => (
                            <Card key={`${rec.id}-${index}`} className="transition-all duration-300 hover:shadow-xl hover:-translate-y-1">
                                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                    <div className="md:col-span-2">
                                        <div className="flex items-center gap-3">
                                            {rec.type === 'cluster' ? <TourismClusterIcon className="w-8 h-8 text-brand-green dark:text-brand-dark-green-text" /> : <EventsCalendarIcon className="w-8 h-8 text-brand-green dark:text-brand-dark-green-text" />}
                                            <div>
                                                <span className="text-xs uppercase font-semibold text-brand-text-secondary-light dark:text-brand-text-secondary">{rec.type}</span>
                                                <h3 className="text-xl font-bold text-brand-text-light dark:text-brand-text">{rec.name}</h3>
                                            </div>
                                        </div>
                                        <p className="mt-1 text-sm flex items-center text-brand-text-secondary-light dark:text-brand-text-secondary">
                                            <MapPinIcon className="w-4 h-4 mr-1.5 flex-shrink-0" />
                                            {rec.location}
                                        </p>
                                        <p className="mt-3 text-sm text-brand-text-light dark:text-brand-text">
                                            <span className="font-semibold">Justification:</span> {rec.justification}
                                        </p>
                                    </div>
                                    <div className="md:col-span-1 flex flex-col md:items-end justify-center gap-2">
                                        <Button variant="secondary" size="sm" onClick={() => handleViewDetails(rec)} className="w-full md:w-auto">View Details</Button>
                                        <Button
                                            variant="primary"
                                            size="sm"
                                            onClick={() => handleAddToItinerary(rec)}
                                            isLoading={addingItemId === rec.id}
                                            leftIcon={<PlusIcon className="w-4 h-4" />}
                                            className="w-full md:w-auto"
                                        >
                                            Add to Itinerary
                                        </Button>
                                    </div>
                                </div>
                            </Card>
                        ))}
                    </div>
                )}
            </div>
            <div className="lg:col-span-1 space-y-6">
                <MyItinerary />
            </div>
        </div>
        {viewingCluster && (
            <ClusterDetailModal
                cluster={viewingCluster}
                onClose={() => setViewingCluster(null)}
            />
        )}
        <InteractiveGuide steps={aiPlannerTourSteps} isOpen={isGuideActive} onClose={() => setIsGuideActive(false)} />
        </>
    );
};

