    const [selectedClusterId, setSelectedClusterId] = useState<string | null>(null);
    const [mode, setMode] = useState<'view' | 'edit'>('view');
    const [editFormData, setEditFormData] = useState<Partial<AddClusterData>>({});
    const [imageFile, setImageFile] = useState<File | null>(null);
    const [isSaving, setIsSaving] = useState(false);
    const [isSavingVisibility, setIsSavingVisibility] = useState(false);
    const [isGenerating, setIsGenerating] = useState(false);
    const [useCustomAddress, setUseCustomAddress] = useState(false);
    const [analyticsData, setAnalyticsData] = useState<{ date: string, views: number, clicks: number }[]>([]);
    const [isAnalyticsLoading, setIsAnalyticsLoading] = useState(false);

    const [products, setProducts] = useState<ClusterProduct[]>([]);
    const [isLoadingProducts, setIsLoadingProducts] = useState(false);
    const [isProductModalOpen, setIsProductModalOpen] = useState(false);
    const [productToEdit, setProductToEdit] = useState<ClusterProduct | null>(null);
    const [productToDelete, setProductToDelete] = useState<ClusterProduct | null>(null);
    const [isDeletingProduct, setIsDeletingProduct] = useState(false);
    const [isTransferModalOpen, setIsTransferModalOpen] = useState(false);

    // New state for deleting a cluster
    const [clusterToDelete, setClusterToDelete] = useState<Cluster | null>(null);
    const [isDeletingCluster, setIsDeletingCluster] = useState(false);
    const [deleteConfirmText, setDeleteConfirmText] = useState('');
    const [isGuideActive, setIsGuideActive] = useState(false);

    useEffect(() => {
        const guideToStart = sessionStorage.getItem('startGuideFor');
        if (guideToStart === ViewName.ManageMyClusters) {
            setIsGuideActive(true);
            sessionStorage.removeItem('startGuideFor');
        }
    }, []);

    const isAdminOrEditor = useMemo(() => currentUser?.role === 'Admin' || currentUser?.role === 'Editor', [currentUser]);
    const isSuperAdmin = useMemo(() => currentUser?.role === 'Admin', [currentUser]);

    const userClusters = useMemo(() => {
        if (!currentUser) return [];
        if (isAdminOrEditor) return clusters;
        return clusters.filter(c => c.owner_id === currentUser.id);
    }, [clusters, currentUser, isAdminOrEditor]);

    const clusterOptions = useMemo(() => {
        return userClusters.map(c => ({ value: c.id, label: `${c.name}${c.is_hidden ? ' (Hidden)' : ''}` }));
    }, [userClusters]);

    const selectedCluster = useMemo(() => {
        return clusters.find(c => c.id === selectedClusterId);
    }, [clusters, selectedClusterId]);

    const clusterOwner = useMemo(() => {
        if (!selectedCluster?.owner_id) return null;
        return users.find(user => user.id === selectedCluster.owner_id);
    }, [selectedCluster, users]);

    useEffect(() => {
        if (!selectedClusterId && userClusters.length > 0) {
            setSelectedClusterId(userClusters[0].id);
        }
         if (selectedClusterId && !userClusters.some(c => c.id === selectedClusterId)) {
            setSelectedClusterId(userClusters[0]?.id || null);
        }
    }, [userClusters, selectedClusterId]);

    const loadProducts = useCallback(async () => {
        if (!selectedClusterId) return;
        setIsLoadingProducts(true);
        try {
            const fetchedProducts = await fetchProductsForCluster(selectedClusterId);
            setProducts(fetchedProducts);
        } finally {
            setIsLoadingProducts(false);
        }
    }, [selectedClusterId, fetchProductsForCluster]);

    useEffect(() => {
        if (selectedClusterId) {
            setMode('view');
            loadProducts();
            setIsAnalyticsLoading(true);
            getDailyClusterAnalytics(selectedClusterId, 30).then(data => {
                setAnalyticsData(data);
                setIsAnalyticsLoading(false);
            });
        }
    }, [selectedClusterId, getDailyClusterAnalytics, loadProducts]);

    const handleEditClick = () => {
        if (!selectedCluster) return;
        setEditFormData({ ...selectedCluster, category: [...selectedCluster.category] });
        if (selectedCluster.location !== selectedCluster.display_address) {
            setUseCustomAddress(true);
        } else {
            setUseCustomAddress(false);
        }
        setMode('edit');
    };

    const handleCancelEdit = () => {
        setMode('view');
        setImageFile(null);
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        const { name, value } = e.target;
        setEditFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleCategoryChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { value, checked } = e.target;
        setEditFormData(prev => {
            const currentCategories = Array.isArray(prev.category) ? prev.category : [];
            const newCategories = checked ? [...currentCategories, value] : currentCategories.filter(c => c !== value);
            return { ...prev, category: newCategories };
        });
    };

    const handleLocationChange = useCallback((location: { lat: number, lng: number, address: string }) => {
        setEditFormData(prev => ({
            ...prev,
            latitude: location.lat,
            longitude: location.lng,
            display_address: location.address,
            ...(!useCustomAddress && { location: location.address })
        }));
    }, [useCustomAddress]);

    const handleGenerateDescription = async () => {
        if (!editFormData.name) {
            showToast("Please provide a Cluster Name first.", "info");
            return;
        }
        setIsGenerating(true);
        try {
            const description = await generateClusterDescription(editFormData.name, Array.isArray(editFormData.category) ? editFormData.category : [], '');
            setEditFormData(prev => ({ ...prev, description }));
            showToast("Description generated!", "success");
        } catch (error) {
            showToast(`Failed to generate description: ${getFormattedError(error)}`, "error");
        } finally {
            setIsGenerating(false);
        }
    };

    const handleSave = async () => {
        if (!selectedCluster) return;
        const finalLocation = useCustomAddress ? editFormData.location : editFormData.display_address;
        if (!editFormData.name || !finalLocation || !editFormData.description) {
            showToast("Name, Location, and Description are required.", "error");
            return;
        }
        setIsSaving(true);
        try {
            let imageUrl = selectedCluster.image;
            if (imageFile) {
                imageUrl = await uploadClusterImage(imageFile, selectedCluster.image);
            }
            await updateCluster(selectedCluster.id, {
                ...editFormData,
                image: imageUrl,
                location: finalLocation,
            });
            setMode('view');
        } finally {
            setIsSaving(false);
        }
    };

    const handleToggleVisibility = async () => {
        if (!selectedCluster) return;
        setIsSavingVisibility(true);
        try {
            await updateCluster(selectedCluster.id, {
                is_hidden: !selectedCluster.is_hidden,
            });
            showToast(`Cluster is now ${!selectedCluster.is_hidden ? 'hidden from public view' : 'visible to the public'}.`, 'success');
        } finally {
            setIsSavingVisibility(false);
        }
    };

    const handleAddProductClick = () => {
        setProductToEdit(null);
        setIsProductModalOpen(true);
    };

    const handleEditProductClick = (product: ClusterProduct) => {
        setProductToEdit(product);
        setIsProductModalOpen(true);
    };

    const handleDeleteProduct = async () => {
        if (!productToDelete) return;
        setIsDeletingProduct(true);
        await deleteProduct(productToDelete.id, productToDelete.image_url);
        setProductToDelete(null);
        await loadProducts();
        setIsDeletingProduct(false);
    };

    const handleConfirmDeleteCluster = async () => {
        if (!clusterToDelete || deleteConfirmText !== clusterToDelete.name) {
            showToast("Confirmation text does not match.", "error");
            return;
        }
        setIsDeletingCluster(true);
        const success = await deleteCluster(clusterToDelete.id);
        if (success) {
            showToast(`Cluster "${clusterToDelete.name}" has been deleted.`, "success");
            setClusterToDelete(null);
            setDeleteConfirmText('');
        }
        setIsDeletingCluster(false);
    };

    const handleExportToCsv = useCallback(() => {
        if (userClusters.length === 0) {
            showToast("No data available to export.", "info");
            return;
        }

        const headers = [
            'ID', 'Name', 'Location', 'Description', 'Categories', 
            'Operating Hours', 'Rating', 'Review Count', 'Views', 'Clicks', 
            'Is Hidden', 'Is Preferred', 'Created At'
        ];

        const csvContent = [
            headers.join(','),
            ...userClusters.map(c => {
                const row = [
                    c.id,
                    `"${c.name.replace(/"/g, '""')}"`,
                    `"${(c.display_address || c.location).replace(/"/g, '""')}"`,
                    `"${c.description.replace(/"/g, '""').replace(/\n/g, ' ')}"`,
                    `"${c.category.join('; ')}"`,
                    `"${(c.timing || '').replace(/"/g, '""')}"`,
                    c.average_rating,
                    c.review_count,
                    c.view_count,
                    c.click_count,
                    c.is_hidden ? 'Yes' : 'No',
                    c.is_preferred ? 'Yes' : 'No',
                    new Date(c.created_at).toLocaleDateString()
                ];
                return row.join(',');
            })
        ].join('\n');

        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement('a');
        const url = URL.createObjectURL(blob);
        link.setAttribute('href', url);
        link.setAttribute('download', `managed_clusters_export_${new Date().toISOString().split('T')[0]}.csv`);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        showToast("Managed clusters exported successfully.", "success");
    }, [userClusters, showToast]);

    const chartColors = useMemo(() => ({
        axisStroke: theme === 'dark' ? '#A0A0A0' : '#566573',
        gridStroke: theme === 'dark' ? '#333333' : '#DEE2E6',
        tooltipBg: theme === 'dark' ? '#252525' : '#FFFFFF',
        tooltipBorder: theme === 'dark' ? '#333333' : '#DEE2E6',
        lineViews: theme === 'dark' ? '#4DBA87' : '#2ECC71',
        lineClicks: theme === 'dark' ? '#F9FAFB' : '#000000',
    }), [theme]);
    const chartTextStyle = { fill: chartColors.axisStroke, fontSize: 12 };

    if (userClusters.length === 0 && !isAdminOrEditor) {
        return (
            <div className="text-center py-12">
                <h2 className="text-xl font-semibold text-brand-text-light dark:text-brand-text">No Clusters to Manage</h2>
                <p className="mt-2 text-brand-text-secondary-light dark:text-brand-text-secondary">
                    You have not added any tourism clusters yet.
                </p>
                <Button className="mt-4" onClick={() => setCurrentView(ViewName.TourismCluster)}>Add Your First Cluster</Button>
            </div>
        );
    }

    return (
        <>
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row justify-between items-center gap-4">
                <div className="flex items-center gap-3">
                    <h2 className="text-2xl font-semibold text-brand-text-light dark:text-brand-text mb-1">Manage My Clusters</h2>
                    <button onClick={() => setIsGuideActive(true)} title="Start Interactive Guide for this page" className="text-brand-text-secondary-light dark:text-brand-text-secondary hover:text-brand-green-text dark:hover:text-brand-dark-green-text">
                        <QuestionMarkCircleIcon className="w-6 h-6" />
                    </button>
                </div>
                <div className="flex items-center gap-2 flex-wrap justify-center">
                    {isSuperAdmin && (
                         <Button variant="secondary" onClick={handleExportToCsv} leftIcon={<DownloadIcon className="w-5 h-5"/>}>Export Clusters</Button>
                    )}
                    {mode === 'view' && (
                        <Button variant="secondary" onClick={() => setCurrentView(ViewName.TourismCluster)}>
                            Back to All Clusters
                        </Button>
                    )}
                </div>
            </div>

            <Card id="cluster-selector-card">
                <Select label="Select a Cluster to Manage" options={clusterOptions} value={selectedClusterId || ''} onChange={(e) => setSelectedClusterId(e.target.value)} />
            </Card>

            {!selectedCluster ? (
                 <div className="text-center py-10">
                    {clusters.length > 0 ? <Spinner /> : <p>No clusters available to manage.</p>}
                </div>
            ) : (
                <>
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    <Card id="cluster-details-card" title="Cluster Details" className="lg:col-span-1" actions={
                        mode === 'view' ? (
                            <div className="flex gap-2">
                                <Button variant="secondary" size="sm" onClick={() => setClusterToDelete(selectedCluster)}>Delete</Button>
                                <Button variant="primary" size="sm" onClick={handleEditClick} leftIcon={<PencilIcon className="w-4 h-4" />}>Edit</Button>
                            </div>
                        ) : (
                            <Button variant="ghost" size="sm" onClick={handleCancelEdit} leftIcon={<ArrowUturnLeftIcon className="w-4 h-4" />}>Cancel</Button>
                        )
                    }>
                        {mode === 'view' ? (
                            <div className="space-y-4">
                                <img src={selectedCluster.image} alt={selectedCluster.name} className="w-full h-40 object-cover rounded-lg" />
                                <InfoRow label="Cluster Name">
                                    <div className="flex items-center gap-2">
                                        <span>{selectedCluster.name}</span>
                                        {selectedCluster.is_hidden && (
                                            <span className="px-2 py-0.5 text-xs font-semibold rounded-full bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-200">
                                                Hidden
                                            </span>
                                        )}
                                    </div>
                                </InfoRow>
                                {isAdminOrEditor && clusterOwner && (
                                     <InfoRow label="Current Owner">{clusterOwner.name} ({clusterOwner.email})</InfoRow>
                                )}
                                <InfoRow label="Location">{selectedCluster.display_address || selectedCluster.location}</InfoRow>
                                <InfoRow label="Description"><p className="whitespace-pre-wrap">{selectedCluster.description}</p></InfoRow>
                                <InfoRow label="Categories">
                                    <div className="flex flex-wrap gap-2">
                                        {selectedCluster.category.map(c => <span key={c} className="px-2 py-1 text-xs rounded-full bg-neutral-200-light dark:bg-neutral-700-dark">{c}</span>)}
                                    </div>
                                </InfoRow>
                                <InfoRow label="Operating Hours">{selectedCluster.timing}</InfoRow>
                                {isAdminOrEditor && (
                                    <div className="pt-4 border-t border-neutral-200-light dark:border-neutral-700-dark space-y-3">
                                        <h4 className="font-semibold">Admin Controls</h4>
                                        <div className="flex items-center justify-between p-3 bg-neutral-100-light dark:bg-neutral-800-dark rounded-lg">
                                            <div>
                                                <h5 className="font-semibold text-brand-text-light dark:text-brand-text">
                                                    Cluster Visibility
                                                </h5>
                                                <p className="text-sm text-brand-text-secondary-light dark:text-brand-text-secondary">
                                                    {selectedCluster.is_hidden ? 'This cluster is hidden from public view.' : 'This cluster is visible to the public.'}
                                                </p>
                                            </div>
                                            <Button
                                                variant={selectedCluster.is_hidden ? 'primary' : 'outline'}
                                                onClick={handleToggleVisibility}
                                                isLoading={isSavingVisibility}
                                            >
                                                {selectedCluster.is_hidden ? 'Make Visible' : 'Hide'}
                                            </Button>
                                        </div>
                                        <div className="pt-2">
                                            <Button variant="outline" onClick={() => setIsTransferModalOpen(true)}>
                                                Transfer Ownership
                                            </Button>
                                        </div>
                                    </div>
                                )}
                            </div>
                        ) : (
                            <div className="space-y-4">
                                <Input label="Cluster Name *" name="name" value={editFormData.name || ''} onChange={handleChange} />
                                <div>
                                    <label className="block text-sm font-medium text-brand-text-secondary-light dark:text-brand-text-secondary mb-1">Location *</label>
                                    <MapPicker
                                        initialPosition={editFormData.latitude && editFormData.longitude ? { lat: editFormData.latitude, lng: editFormData.longitude } : null}
                                        onLocationChange={handleLocationChange}
                                        mapContainerClassName="h-64"
                                    />
                                </div>
                                <div className="flex items-center">
                                    <input type="checkbox" id="myClusterUseCustomAddress" checked={useCustomAddress} onChange={(e) => setUseCustomAddress(e.target.checked)} className="h-4 w-4 rounded border-gray-300 text-brand-green focus:ring-brand-green" />
                                    <label htmlFor="myClusterUseCustomAddress" className="ml-2 text-sm">Use a custom display address</label>
                                </div>
                                {useCustomAddress ? (
                                    <Input label="Custom Display Address *" name="location" value={editFormData.location || ''} onChange={handleChange} required />
                                ) : (
                                    <p className="p-2.5 rounded-lg bg-neutral-100-light dark:bg-neutral-700-dark text-sm">{editFormData.display_address || "Click map to set location."}</p>
                                )}
                                <div>
                                    <div className="flex justify-between items-center mb-1">
                                        <label className="block text-sm font-medium">Description *</label>
                                        <Button type="button" variant="ghost" size="sm" onClick={handleGenerateDescription} isLoading={isGenerating} leftIcon={<SparklesIcon className="w-4 h-4" />} aria-label="Generate description with AI">AI Generate</Button>
                                    </div>
                                    <textarea name="description" value={editFormData.description || ''} onChange={handleChange} rows={4} className="w-full rounded-lg p-2.5 bg-input-bg-light dark:bg-input-bg border border-neutral-300-light dark:border-neutral-600-dark" />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium mb-2">Categories *</label>
                                    <div className="grid grid-cols-2 gap-2">
                                        {["Association", "Homestay", "Culture", "Adventure", "Nature", "Foods", "Festivals"].map(cat => (
                                            <label key={cat} className="flex items-center space-x-2">
                                                <input type="checkbox" value={cat} checked={Array.isArray(editFormData.category) && editFormData.category.includes(cat)} onChange={handleCategoryChange} className="h-4 w-4 rounded" />
                                                <span>{cat}</span>
                                            </label>
                                        ))}
                                    </div>
                                </div>
                                <Input label="Operating Hours" name="timing" value={editFormData.timing || ''} onChange={handleChange} />
                                <div>
                                    <label className="block text-sm font-medium mb-1">Image</label>
                                    <FileUpload onFileSelect={setImageFile} />
                                </div>
                                <div className="flex justify-end pt-4 border-t border-neutral-200-light dark:border-neutral-700-dark">
                                    <Button variant="primary" onClick={handleSave} isLoading={isSaving}>Save Changes</Button>
                                </div>
                            </div>
                        )}
                    </Card>

                    <div className="lg:col-span-2 space-y-6">
                        <Card id="cluster-analytics-card" title="Performance Analytics (Last 30 Days)">
                            <div style={{ width: '100%', height: 300 }}>
                                {isAnalyticsLoading ? <Spinner /> : (
                                    <ResponsiveContainer>
                                        <LineChart data={analyticsData}>
                                            <CartesianGrid strokeDasharray="3 3" stroke={chartColors.gridStroke} />
                                            <XAxis dataKey="date" tickFormatter={(tick) => new Date(tick).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} style={chartTextStyle} />
                                            <YAxis style={chartTextStyle} />
                                            <Tooltip contentStyle={{ backgroundColor: chartColors.tooltipBg, border: `1px solid ${chartColors.tooltipBorder}` }} />
                                            <Legend wrapperStyle={{ color: chartColors.axisStroke }} />
                                            <Line type="monotone" dataKey="views" name="Card Views" stroke={chartColors.lineViews} strokeWidth={2} />
                                            <Line type="monotone" dataKey="clicks" name="Detail Clicks" stroke={chartColors.lineClicks} strokeWidth={2} />
                                        </LineChart>
                                    </ResponsiveContainer>
                                )}
                            </div>
                        </Card>
                         <Card id="cluster-products-card" title="Products & Services" actions={
                             <Button variant="primary" size="sm" onClick={handleAddProductClick} leftIcon={<PlusIcon className="w-4 h-4"/>}>Add Product</Button>
                         }>
                             {isLoadingProducts ? (<Spinner/>) : products.length > 0 ? (
                                <div className="space-y-3 max-h-60 overflow-y-auto custom-scrollbar pr-2">
                                    {products.map(product => (
                                        <div key={product.id} className="flex items-center gap-4 p-2 rounded-md bg-neutral-100-light dark:bg-neutral-800-dark">
                                            <img src={product.image_url || ''} alt={product.name} className="w-16 h-16 object-cover rounded-md flex-shrink-0" />
                                            <div className="flex-grow">
                                                <p className="font-semibold">{product.name}</p>
                                                <p className="text-sm font-bold text-brand-green dark:text-brand-dark-green-text">{product.price_range}</p>
                                            </div>
                                            <div className="flex-shrink-0">
                                                <Button variant="ghost" size="sm" onClick={() => handleEditProductClick(product)} aria-label={`Edit ${product.name}`}><PencilIcon className="w-4 h-4"/></Button>
                                                <Button variant="ghost" size="sm" className="text-red-500" onClick={() => setProductToDelete(product)} aria-label={`Delete ${product.name}`}><TrashIcon className="w-4 h-4"/></Button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                             ) : (<p className="text-sm text-center py-4 text-brand-text-secondary-light dark:text-brand-text-secondary">No products added yet.</p>)}
                         </Card>
                    </div>
                </div>
                {isProductModalOpen && (
                    <ProductFormModal 
                        isOpen={isProductModalOpen}
                        onClose={() => setIsProductModalOpen(false)}
                        clusterId={selectedCluster.id}
                        productToEdit={productToEdit}
                        onSaveSuccess={loadProducts}
                    />
                )}
                 {productToDelete && (
                    <Modal isOpen={!!productToDelete} onClose={() => setProductToDelete(null)} title="Confirm Delete Product" size="sm">
                        <p>Are you sure you want to delete the product "{productToDelete.name}"? This cannot be undone.</p>
                        <div className="flex justify-end space-x-3 pt-6">
                            <Button variant="secondary" onClick={() => setProductToDelete(null)} disabled={isDeletingProduct}>Cancel</Button>
                            <Button variant="primary" className="bg-red-600 hover:bg-red-700" onClick={handleDeleteProduct} isLoading={isDeletingProduct}>Delete</Button>
                        </div>
                    </Modal>
                )}
                 {isTransferModalOpen && (
                    <TransferClusterModal
                        isOpen={isTransferModalOpen}
                        onClose={() => setIsTransferModalOpen(false)}
                        cluster={selectedCluster}
                        onTransferSuccess={() => {
                            showToast("Ownership transferred successfully!", "success");
                            setIsTransferModalOpen(false);
                        }}
                    />
                )}
                </>
            )}

            {/* Delete Cluster Confirmation Modal */}
            <Modal
                isOpen={!!clusterToDelete}
                onClose={() => {
                    setClusterToDelete(null);
                    setDeleteConfirmText('');
                }}
                title={`Delete Cluster: ${clusterToDelete?.name}`}
                size="md"
            >
                <div className="space-y-4">
                    <p className="text-brand-text-light dark:text-brand-text">
                        This action is <strong className="text-red-500">irreversible</strong>. It will permanently delete the cluster, its products, and all associated analytics.
                    </p>
                    <p className="text-sm text-brand-text-secondary-light dark:text-brand-text-secondary">
                        To confirm, please type the full name of the cluster below:
                    </p>
                    <p className="p-2.5 rounded-lg bg-neutral-100-light dark:bg-neutral-700-dark text-center font-semibold text-brand-text-light dark:text-brand-text">
                        {clusterToDelete?.name}
                    </p>
                    <Input
                        label="Confirm Cluster Name"
                        value={deleteConfirmText}
                        onChange={(e) => setDeleteConfirmText(e.target.value)}
                        required
                        disabled={isDeletingCluster}
                        placeholder="Type the cluster name here..."
                    />
                    <div className="flex justify-end space-x-3 pt-4">
                        <Button
                            variant="secondary"
                            onClick={() => {
                                setClusterToDelete(null);
                                setDeleteConfirmText('');
                            }}
                            disabled={isDeletingCluster}
                        >
                            Cancel
                        </Button>
                        <Button
                            variant="primary"
                            className="bg-red-600 hover:bg-red-700 dark:bg-red-500 dark:hover:bg-red-600 focus:ring-red-500"
                            isLoading={isDeletingCluster}
                            disabled={isDeletingCluster || deleteConfirmText !== clusterToDelete?.name}
                            onClick={handleConfirmDeleteCluster}
                        >
                            Permanently Delete
                        </Button>
                    </div>
                </div>
            </Modal>
        </div>
        <InteractiveGuide steps={manageMyClustersTourSteps} isOpen={isGuideActive} onClose={() => setIsGuideActive(false)} />
        </>
    );
};

export default ManageMyClustersView;

import { GoogleGenAI, Type } from "@google/genai";
import { AppEvent, Feedback } from '../types.ts';

// Helper to get a formatted error message
const getFormattedError = (err: unknown): string => {
    if (err instanceof Error) {
        const msg = err.message;
        if (msg.includes("CONSUMER_SUSPENDED") || msg.includes("403")) {
            return "The API key being used has been suspended or lacks permissions. Please select a valid API key via the key selection dialog.";
        }
        if (msg.includes("429")) {
            return "The API quota has been reached. Please try again later or use a different API key.";
        }
        return msg;
    }
    if (typeof err === 'string') return err;
    if (err && typeof err === 'object' && 'message' in err && typeof (err as any).message === 'string') {
        const apiError = err as { message: string; details?: string; hint?: string; code?: string };
        return `API Error: ${apiError.message}${apiError.details ? ` Details: ${apiError.details}` : ''}`;
    }
    try {
        return `An unexpected error occurred: ${JSON.stringify(err)}`;
    } catch {
        return 'An unknown and un-serializable error occurred.';
    }
};

/**
 * Summarizes system feedback for admins.
 */
export const summarizeFeedbackAI = async (feedbacks: Feedback[]): Promise<{ summary: string; sentiment: 'Positive' | 'Mixed' | 'Negative'; priorities: string[] }> => {
    if (feedbacks.length === 0) return { summary: "No feedback to analyze.", sentiment: 'Mixed', priorities: [] };

    // Create a new instance right before the call to ensure latest API Key is used
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
        const feedbackText = feedbacks.map(f => `- ${f.content}`).join('\n');
        const prompt = `Analyze the following user feedback for the INTOURCAMS Sarawak Tourism system. 
        Provide a concise executive summary, determine the overall sentiment, and list the top 3 priorities for developers.

        Feedback:
        ${feedbackText}`;

        const responseSchema = {
            type: Type.OBJECT,
            properties: {
                summary: { type: Type.STRING },
                sentiment: { type: Type.STRING, enum: ['Positive', 'Mixed', 'Negative'] },
                priorities: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["summary", "sentiment", "priorities"]
        };

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: responseSchema,
            },
        });

        if (!response.text) throw new Error("No response text from AI.");
        return JSON.parse(response.text);
    } catch (error) {
        console.error("AI Feedback Analysis Failed", error);
        throw new Error(getFormattedError(error));
    }
};

/**
 * Generates a marketing description for a tourism cluster.
 * Uses Gemini 3 Flash for high-speed, cost-effective creative writing.
 */
export const generateClusterDescription = async (name: string, categories: string[], vibe: string): Promise<string> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const prompt = `As a creative tourism copywriter, write a short, engaging marketing description for a tourism spot in Sarawak, Malaysia named "${name}" which falls under the categories "${categories.join(', ')}". ${vibe ? `The desired tone is "${vibe}". Craft the description in a compelling, ${vibe} style.` : ''} Highlight its key attractions in 2-3 concise sentences.`;

        const response = await ai.models.generateContent({ 
            model: 'gemini-3-flash-preview', 
            contents: prompt 
        });

        if (!response.text) throw new Error("No response text from AI.");
        return response.text.trim();
    } catch (error) {
        throw new Error(getFormattedError(error));
    }
};

/**
 * Generates an analytical summary for events in a given year.
 */
type GroundingChunk = { web?: { uri?: string; title?: string } };
export const generateEventAnalyticsInsight = async (events: AppEvent[], year: number): Promise<{ summary: string; sources: GroundingChunk[] }> => {
    if (events.length === 0) {
        return { summary: "No event data for this year to analyze.", sources: [] };
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const eventTitles = events.map(e => e.title).slice(0, 100).join(', ');
        const prompt = `Analyze Sarawak events for ${year}. Data: ${eventTitles}. Focus on trends and cultural impact.`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: prompt,
            config: {
                tools: [{ googleSearch: {} }],
            },
        });

        const summary = response.text || "No summary available.";
        const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

        return { summary, sources };
    } catch (error) {
        console.error("Event Analytics Insight Failed", error);
        return { summary: "Could not generate AI insights: " + getFormattedError(error), sources: [] };
    }
};

/**
 * Generates trip recommendations based on user preferences.
 */
interface Recommendation {
    id: string;
    type: 'cluster' | 'event';
    name: string;
    justification: string;
    location: string;
}
export const generateItineraryRecommendations = async (preferences: any, items: any[]): Promise<Recommendation[]> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const dataForAI = items.map(item => ({
            id: item.id,
            type: item.itemType,
            name: item.name || item.title,
            location: item.display_address || item.location || item.location_name
        }));

        const prompt = `Recommend 5 Sarawak trip items for: ${preferences.location}, ${preferences.duration} days. Items: ${JSON.stringify(dataForAI)}`;

        const responseSchema = {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    id: { type: Type.STRING },
                    type: { type: Type.STRING },
                    name: { type: Type.STRING },
                    location: { type: Type.STRING },
                    justification: { type: Type.STRING }
                },
                required: ["id", "type", "name", "location", "justification"]
            }
        };

        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: responseSchema,
            },
        });

        if (!response.text) throw new Error("No response text from AI.");
        return JSON.parse(response.text);
    } catch (error) {
        console.error("Itinerary Recommendations Failed", error);
        throw new Error(getFormattedError(error));
    }
};

