import { GoogleGenAI, Type } from "@google/genai";
import { AppEvent, Feedback } from '../types.ts';

// Helper to get a formatted error message for AI operations
const getFormattedError = (err: unknown): string => {
    if (err instanceof Error) {
        const msg = err.message;
        // Specifically detect the suspension error reported by the user
        if (msg.includes("CONSUMER_SUSPENDED") || msg.includes("403") || msg.includes("Permission denied")) {
            return "The current API key is suspended. Please select a valid API key from a paid GCP project to continue.";
        }
        if (msg.includes("429")) {
            return "API Quota exceeded. Please try again later or use a different API key.";
        }
        return msg;
    }
    return "An unexpected AI error occurred.";
};

/**
 * Summarizes system feedback for admins.
 */
export const summarizeFeedbackAI = async (feedbacks: Feedback[]): Promise<{ summary: string; sentiment: 'Positive' | 'Mixed' | 'Negative'; priorities: string[] }> => {
    if (feedbacks.length === 0) return { summary: "No feedback to analyze.", sentiment: 'Mixed', priorities: [] };

    // New instance per call to ensure latest environment key
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
        const feedbackText = feedbacks.map(f => `- ${f.content}`).join('\n');
        const prompt = `Analyze user feedback for the INTOURCAMS Sarawak Tourism system. Provide a summary, sentiment, and top 3 priorities.
        Feedback:
        ${feedbackText}`;

        const responseSchema = {
            type: Type.OBJECT,
            properties: {
                summary: { type: Type.STRING },
                sentiment: { type: Type.STRING, enum: ['Positive', 'Mixed', 'Negative'] },
                priorities: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["summary", "sentiment", "priorities"]
        };

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: responseSchema,
            },
        });

        if (!response.text) throw new Error("Empty response from AI.");
        return JSON.parse(response.text);
    } catch (error) {
        throw new Error(getFormattedError(error));
    }
};

/**
 * Generates a marketing description for a tourism cluster.
 */
export const generateClusterDescription = async (name: string, categories: string[], vibe: string): Promise<string> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const prompt = `Write a short, engaging description for a Sarawak tourism spot: "${name}" (${categories.join(', ')}). Tone: ${vibe || 'inviting'}. 2-3 sentences.`;
        const response = await ai.models.generateContent({ 
            model: 'gemini-3-flash-preview', 
            contents: prompt 
        });
        return response.text?.trim() || "No description generated.";
    } catch (error) {
        throw new Error(getFormattedError(error));
    }
};

/**
 * Generates an analytical summary for events.
 */
export const generateEventAnalyticsInsight = async (events: AppEvent[], year: number): Promise<{ summary: string; sources: any[] }> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const titles = events.map(e => e.title).join(', ');
        const prompt = `Analyze Sarawak events for ${year}: ${titles}. Provide a strategic summary of trends.`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: prompt,
            config: { tools: [{ googleSearch: {} }] },
        });

        return { 
            summary: response.text || "No insights available.", 
            sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || [] 
        };
    } catch (error) {
        throw new Error(getFormattedError(error));
    }
};

/**
 * Generates trip recommendations based on user preferences.
 */
export const generateItineraryRecommendations = async (preferences: any, items: any[]): Promise<any[]> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
        const prompt = `Recommend 5 items from this list for a ${preferences.duration}-day trip to ${preferences.location || 'Sarawak'}: ${JSON.stringify(items)}`;

        const responseSchema = {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    id: { type: Type.STRING },
                    type: { type: Type.STRING },
                    name: { type: Type.STRING },
                    location: { type: Type.STRING },
                    justification: { type: Type.STRING }
                },
                required: ["id", "type", "name", "location", "justification"]
            }
        };

        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: responseSchema,
            },
        });

        return JSON.parse(response.text || "[]");
    } catch (error) {
        throw new Error(getFormattedError(error));
    }
};

