const AIPlannerView: React.FC<AIPlannerViewProps> = ({ setCurrentView, onAuthRequired }) => {
    const { clusters, events, currentUser, addItineraryItem } = useAppContext();

    const [preferences, setPreferences] = useState({
        location: '',
        activities: new Set<string>(),
        duration: 3,
        budget: 500,
    });
    const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [addingItemId, setAddingItemId] = useState<string | null>(null);
    const [viewingCluster, setViewingCluster] = useState<Cluster | null>(null);
    const [isGuideActive, setIsGuideActive] = useState(false);

    // API Key flow
    const [isKeySuspended, setIsKeySuspended] = useState(false);

    const handleSelectApiKey = async () => {
        if (window.aistudio?.openSelectKey) {
            await window.aistudio.openSelectKey();
            setIsKeySuspended(false);
            setError(null);
            // Optionally auto-retry
            handleGetRecommendations();
        }
    };

    const handleGetRecommendations = async () => {
        setIsLoading(true);
        setError(null);
        setRecommendations([]);

        try {
            const locationLower = preferences.location.toLowerCase();
            const selectedActivities = Array.from(preferences.activities).map(a => String(a).toLowerCase());

            const relevantClusters = clusters.filter(c => {
                const matchesLocation = !locationLower || (c.display_address || c.location).toLowerCase().includes(locationLower);
                const matchesActivity = selectedActivities.length === 0 || c.category.some(cat => selectedActivities.includes(String(cat).toLowerCase()));
                return matchesLocation && matchesActivity;
            });

            const relevantEvents = events.filter(e => {
                const matchesLocation = !locationLower || (e.display_address || e.location_name).toLowerCase().includes(locationLower);
                const matchesActivity = selectedActivities.length === 0 || selectedActivities.includes(e.category.toLowerCase());
                return matchesLocation && matchesActivity;
            });

            const allRelevantItems = [
                ...relevantClusters.map(c => ({ ...c, itemType: 'cluster' as const })),
                ...relevantEvents.map(e => ({ ...e, itemType: 'event' as const }))
            ];

            const selectedItems = allRelevantItems.sort(() => 0.5 - Math.random()).slice(0, 30);

            if (selectedItems.length === 0) {
                 setError("No matching spots found. Try a broader search.");
                 setIsLoading(false);
                 return;
            }

            const result = await generateItineraryRecommendations(preferences, selectedItems);
            setRecommendations(result);
            setIsKeySuspended(false);

        } catch (err: any) {
            const msg = err.message || "";
            if (msg.includes("suspended") || msg.includes("403") || msg.includes("Permission denied")) {
                setIsKeySuspended(true);
                setError("The system API key is currently suspended.");
            } else {
                setError(`AI generation failed: ${msg}`);
            }
        } finally {
            setIsLoading(false);
        }
    };

    const handleViewDetails = (item: Recommendation) => {
        if (item.type === 'cluster') {
            const fullCluster = clusters.find(c => c.id === item.id);
            if (fullCluster) setViewingCluster(fullCluster);
            else {
                sessionStorage.setItem('initialClusterSearch', item.name);
                setCurrentView(ViewName.TourismCluster);
            }
        } else {
            sessionStorage.setItem('initialEventSearch', item.name);
            setCurrentView(ViewName.EventsCalendar);
        }
    };

    return (
        <>
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 items-start">
            <div className="lg:col-span-2 space-y-6">
                <Card title="AI Trip Planner" titleIcon={<SparklesIcon className="w-6 h-6" />}>
                    <div id="ai-planner-form" className="space-y-6">
                        {isKeySuspended && (
                            <div className="p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg flex flex-col items-center text-center gap-3">
                                <p className="text-sm text-red-800 dark:text-red-200 font-medium">
                                    The system API key is suspended. To continue, please select your own Gemini API key.
                                </p>
                                <div className="flex gap-3">
                                    <Button variant="primary" size="sm" onClick={handleSelectApiKey}>Select My API Key</Button>
                                    <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noopener noreferrer" className="inline-flex items-center text-xs text-brand-green dark:text-brand-dark-green-text hover:underline">
                                        Setup Billing Info <QuestionMarkCircleIcon className="w-3 h-3 ml-1"/>
                                    </a>
                                </div>
                            </div>
                        )}

                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                            <Input label="Location" placeholder="Kuching, Miri..." value={preferences.location} onChange={e => setPreferences(p => ({ ...p, location: e.target.value }))} />
                            <Input label="Days" type="number" min="1" value={String(preferences.duration)} onChange={e => setPreferences(p => ({ ...p, duration: parseInt(e.target.value, 10) || 1 }))} />
                            <Input label="Budget (RM)" type="number" min="0" value={String(preferences.budget)} onChange={e => setPreferences(p => ({ ...p, budget: parseInt(e.target.value, 10) || 0 }))} />
                        </div>
                        <div>
                            <label className="block text-sm font-medium mb-2">Interests</label>
                            <div className="flex flex-wrap gap-2">
                                {activityOptions.map(activity => (
                                    <button
                                        key={activity}
                                        onClick={() => {
                                            const next = new Set(preferences.activities);
                                            if (next.has(activity)) next.delete(activity);
                                            else next.add(activity);
                                            setPreferences(p => ({ ...p, activities: next }));
                                        }}
                                        className={`px-3 py-1.5 text-sm rounded-full transition-colors ${preferences.activities.has(activity) ? 'bg-brand-green text-white' : 'bg-neutral-200-light dark:bg-neutral-700-dark'}`}
                                    >
                                        {activity}
                                    </button>
                                ))}
                            </div>
                        </div>
                        <div id="get-recommendations-btn" className="flex justify-end">
                            <Button variant="primary" size="lg" onClick={handleGetRecommendations} isLoading={isLoading} leftIcon={<SparklesIcon className="w-5 h-5" />} disabled={isKeySuspended}>
                                Get Recommendations
                            </Button>
                        </div>
                    </div>
                </Card>

                {error && !isKeySuspended && <Card><p className="text-center text-red-500 py-4">{error}</p></Card>}

                {recommendations.length > 0 && (
                    <div className="space-y-6 animate-modalShow">
                        <h2 className="text-2xl font-semibold text-brand-text-light dark:text-brand-text">Your Personalized Plan</h2>
                        {recommendations.map((rec, index) => (
                            <Card key={index} className="hover:shadow-lg transition-shadow">
                                <div className="flex flex-col md:flex-row justify-between gap-4">
                                    <div className="space-y-2">
                                        <div className="flex items-center gap-2">
                                            {rec.type === 'cluster' ? <TourismClusterIcon className="w-5 h-5 text-brand-green"/> : <EventsCalendarIcon className="w-5 h-5 text-brand-green"/>}
                                            <h3 className="text-xl font-bold">{rec.name}</h3>
                                        </div>
                                        <p className="text-sm text-brand-text-secondary flex items-center"><MapPinIcon className="w-4 h-4 mr-1"/> {rec.location}</p>
                                        <p className="text-sm italic">"{rec.justification}"</p>
                                    </div>
                                    <div className="flex flex-row md:flex-col gap-2 justify-end">
                                        <Button variant="secondary" size="sm" onClick={() => handleViewDetails(rec)}>Details</Button>
                                        <Button variant="primary" size="sm" onClick={async () => {
                                            if (!currentUser) onAuthRequired?.("Please log in to save to your itinerary.");
                                            else {
                                                setAddingItemId(rec.id);
                                                await addItineraryItem(rec.id, rec.type, rec.name);
                                                setAddingItemId(null);
                                            }
                                        }} isLoading={addingItemId === rec.id}>Add</Button>
                                    </div>
                                </div>
                            </Card>
                        ))}
                    </div>
                )}
            </div>
            <div className="lg:col-span-1"><MyItinerary /></div>
        </div>
        {viewingCluster && <ClusterDetailModal cluster={viewingCluster} onClose={() => setViewingCluster(null)} />}
        <InteractiveGuide steps={aiPlannerTourSteps} isOpen={isGuideActive} onClose={() => setIsGuideActive(false)} />
        </>
    );
};

