const ClusterCard: React.FC<{
    cluster: Cluster;
    onSelect: (cluster: Cluster) => void;
    onViewed: (clusterId: string) => void;
    hasBeenViewed: boolean;
    isAdmin: boolean;
    className?: string;
}> = ({ cluster, onSelect, onViewed, hasBeenViewed, isAdmin, className }) => {
    const { incrementClusterView } = useAppContext();
    const cardRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (hasBeenViewed) return;

        const observer = new IntersectionObserver(
            ([entry]) => {
                if (entry.isIntersecting) {
                    incrementClusterView(cluster.id);
                    onViewed(cluster.id);
                    observer.disconnect();
                }
            },
            { threshold: 0.5 }
        );

        const currentRef = cardRef.current;
        if (currentRef) observer.observe(currentRef);

        return () => {
            if (currentRef) observer.unobserve(currentRef);
            observer.disconnect();
        };
    }, [cluster.id, incrementClusterView, onViewed, hasBeenViewed]);

    const googleMapsUrl = (cluster.latitude && cluster.longitude)
        ? `https://www.google.com/maps/search/?api=1&query=${cluster.latitude},${cluster.longitude}`
        : `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(cluster.display_address || cluster.location)}`;

    return (
        <button
            ref={cardRef as any}
            onClick={() => onSelect(cluster)}
            className={`w-full text-left bg-card-bg-light dark:bg-card-bg rounded-lg shadow-md hover:shadow-xl border border-neutral-300-light dark:border-neutral-700-dark transition-all duration-300 hover:-translate-y-1 overflow-hidden ${className}`}
            aria-label={`View details for ${cluster.name}`}
        >
            <div className="h-40 bg-neutral-200-light dark:bg-neutral-800-dark">
                <img src={cluster.image} alt={cluster.name} className="w-full h-full object-cover" />
            </div>
            <div className="p-4">
                 <div className="flex items-center gap-2 mb-1">
                    <h3 className="font-bold text-lg text-brand-text-light dark:text-brand-text truncate" title={cluster.name}>
                        {cluster.name}
                    </h3>
                    {isAdmin && cluster.is_hidden && (
                        <span className="flex-shrink-0 text-xs font-semibold px-2 py-0.5 rounded-full bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-200">
                            Hidden
                        </span>
                    )}
                </div>
                <a
                    href={googleMapsUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="mt-1 text-sm text-brand-text-secondary-light dark:text-brand-text-secondary truncate flex items-center hover:text-brand-green dark:hover:text-brand-dark-green-text hover:underline"
                    onClick={(e) => e.stopPropagation()}
                    title={`Open in Google Maps: ${cluster.display_address || cluster.location}`}
                >
                    <MapPinIcon className="w-4 h-4 mr-1.5 flex-shrink-0" />
                    <span title={cluster.display_address || cluster.location}>{cluster.display_address || cluster.location}</span>
                </a>

                <div className="mt-2">
                    <StarRating rating={cluster.average_rating} reviewCount={cluster.review_count} size="sm" />
                </div>
            </div>
        </button>
    );
};

const tourismClustersTourSteps = [
    { selector: '#cluster-search-filter', title: 'Search & Filter', content: 'Quickly find clusters by name or location using the search bar. You can also filter the results by category or district using the dropdowns.' },
    { selector: '#add-cluster-buttons', title: 'Add New Clusters', content: 'If you have permission, you can add a single new cluster or perform a batch upload using a CSV file from here.' },
    { selector: '.cluster-card-item:first-child', title: 'Cluster Cards', content: 'Each card represents a tourism cluster. Click on a card to view its detailed information, including products, services, and user reviews.' },
];

const TourismClustersView: React.FC<{ setCurrentView: (view: ViewName) => void }> = ({ setCurrentView }) => {
    const { clusters, isLoadingClusters, currentUser, deleteCluster, incrementClusterClick } = useAppContext();
    const { showToast } = useToast();

    const [searchTerm, setSearchTerm] = useState('');
    const [selectedCategory, setSelectedCategory] = useState('All');
    const [selectedDistrict, setSelectedDistrict] = useState('All');
    const [selectedCluster, setSelectedCluster] = useState<Cluster | null>(null);
    const [modalMode, setModalMode] = useState<'details' | 'form' | 'closed'>('closed');
    const [clusterToEdit, setClusterToEdit] = useState<Cluster | null>(null);
    const [clusterToDelete, setClusterToDelete] = useState<Cluster | null>(null);
    const [isDeleting, setIsDeleting] = useState(false);
    const [isBatchUploadModalOpen, setIsBatchUploadModalOpen] = useState(false);
    const [viewedClusters, setViewedClusters] = useState<Set<string>>(new Set());
    const [isGuideActive, setIsGuideActive] = useState(false);

    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(12);

    useEffect(() => {
        const guideToStart = sessionStorage.getItem('startGuideFor');
        if (guideToStart === ViewName.TourismCluster) {
            setIsGuideActive(true);
            sessionStorage.removeItem('startGuideFor');
        }
    }, []);

    useEffect(() => {
        setCurrentPage(1);
    }, [searchTerm, selectedCategory, selectedDistrict, itemsPerPage]);

    const handleClusterViewed = useCallback((clusterId: string) => {
        setViewedClusters(prev => {
            if (prev.has(clusterId)) {
                return prev;
            }
            const newSet = new Set(prev);
            newSet.add(clusterId);
            return newSet;
        });
    }, []);

    useEffect(() => {
        const initialSearch = sessionStorage.getItem('initialClusterSearch');
        if (initialSearch) {
            setSearchTerm(initialSearch);
            sessionStorage.removeItem('initialClusterSearch');
        }
    }, []);

    const canAddCluster = useMemo(() => {
        if (!currentUser) return false;
        const role = currentUser.role;
        return role === 'Admin' || role === 'Editor' || role === 'Tourism Player';
    }, [currentUser]);

    const isAdmin = useMemo(() => currentUser?.role === 'Admin' || currentUser?.role === 'Editor', [currentUser]);

    const filteredClusters = useMemo(() => {
        return clusters.filter(cluster => {
            const matchesCategory = selectedCategory === 'All' || cluster.category.includes(selectedCategory);
            const locationString = `${cluster.location || ''} ${cluster.display_address || ''}`.toLowerCase();
            const matchesDistrict = selectedDistrict === 'All' || locationString.includes(selectedDistrict.toLowerCase());
            const matchesSearch = searchTerm === '' || 
                cluster.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                locationString.includes(searchTerm.toLowerCase());
            return matchesCategory && matchesDistrict && matchesSearch;
        });
    }, [clusters, searchTerm, selectedCategory, selectedDistrict]);

    const totalPages = useMemo(() => Math.ceil(filteredClusters.length / itemsPerPage), [filteredClusters.length, itemsPerPage]);

    const paginatedClusters = useMemo(() => {
        const startIndex = (currentPage - 1) * itemsPerPage;
        return filteredClusters.slice(startIndex, startIndex + itemsPerPage);
    }, [filteredClusters, currentPage, itemsPerPage]);

    const handleSelectCluster = (cluster: Cluster) => {
        incrementClusterClick(cluster.id);
        setSelectedCluster(cluster);
        setModalMode('details');
    };

    const handleOpenAddModal = () => {
        setClusterToEdit(null);
        setModalMode('form');
    };

    const handleEdit = (cluster: Cluster) => {
        setClusterToEdit(cluster);
        setModalMode('form');
    };

    const handleDelete = (cluster: Cluster) => {
        setClusterToDelete(cluster);
        setModalMode('closed');
    };

    const confirmDelete = async () => {
        if (!clusterToDelete) return;
        setIsDeleting(true);
        const success = await deleteCluster(clusterToDelete.id);
        if (success) {
            showToast(`Cluster "${clusterToDelete.name}" deleted successfully.`, "success");
            setClusterToDelete(null);
        }
        setIsDeleting(false);
    };

    const handleCloseModal = () => {
        setModalMode('closed');
        setSelectedCluster(null);
        setClusterToEdit(null);
    };

    const handleCloseBatchModal = () => {
        setIsBatchUploadModalOpen(false);
    }

    const PaginationControls: React.FC = () => {
        if (totalPages <= 1) return null;
        const startIndex = (currentPage - 1) * itemsPerPage + 1;
        const endIndex = Math.min(startIndex + itemsPerPage - 1, filteredClusters.length);
        return (
            <div className="flex flex-col sm:flex-row justify-between items-center gap-4 mt-6">
                 <p className="text-sm text-brand-text-secondary-light dark:text-brand-text-secondary">
                    Showing <span className="font-medium text-brand-text-light dark:text-brand-text">{startIndex}</span> to <span className="font-medium text-brand-text-light dark:text-brand-text">{endIndex}</span> of <span className="font-medium text-brand-text-light dark:text-brand-text">{filteredClusters.length}</span> results
                </p>
                <div className="flex items-center gap-2">
                    <Button variant="secondary" size="sm" onClick={() => setCurrentPage(p => p - 1)} disabled={currentPage === 1}>
                        Previous
                    </Button>
                    <span className="text-sm text-brand-text-secondary-light dark:text-brand-text-secondary">
                        Page {currentPage} of {totalPages}
                    </span>
                    <Button variant="secondary" size="sm" onClick={() => setCurrentPage(p => p + 1)} disabled={currentPage === totalPages}>
                        Next
                    </Button>
                </div>
            </div>
        );
    };

    return (
        <>
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row justify-between items-center gap-4">
                <div className="flex items-center gap-3">
                    <h2 className="text-2xl font-semibold text-brand-text-light dark:text-brand-text mb-1">Tourism Clusters</h2>
                    <button onClick={() => setIsGuideActive(true)} title="Start Interactive Guide for this page" className="text-brand-text-secondary-light dark:text-brand-text-secondary hover:text-brand-green-text dark:hover:text-brand-dark-green-text">
                        <QuestionMarkCircleIcon className="w-6 h-6" />
                    </button>
                </div>
                {canAddCluster && (
                    <div id="add-cluster-buttons" className="flex gap-2">
                         <Button variant="secondary" onClick={() => setIsBatchUploadModalOpen(true)}>Batch Upload</Button>
                         <Button variant="primary" onClick={handleOpenAddModal} leftIcon={<PlusIcon className="w-5 h-5"/>}>Add New Cluster</Button>
                    </div>
                )}
            </div>

            <Card>
                <div id="cluster-search-filter" className="flex flex-col xl:flex-row flex-wrap gap-4 items-center">
                    <Input placeholder="Search by name or location..." icon={<SearchIcon className="w-5 h-5"/>} className="flex-grow" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                    <div className="flex flex-col sm:flex-row gap-4 w-full xl:w-auto">
                        <div className="flex-grow sm:w-64">
                            <Select
                                options={[{ value: 'All', label: 'All Categories' }, ...CLUSTER_CATEGORIES.map(c => ({ value: c.id, label: c.name }))]}
                                value={selectedCategory}
                                onChange={(e) => setSelectedCategory(e.target.value)}
                                className="w-full"
                            />
                        </div>
                        <div className="flex-grow sm:w-64">
                            <Select
                                options={SARAWAK_DISTRICTS.map(d => ({ value: d, label: d === 'All' ? 'All Districts' : d }))}
                                value={selectedDistrict}
                                onChange={(e) => setSelectedDistrict(e.target.value)}
                                className="w-full"
                            />
                        </div>
                    </div>
                    <div className="flex-none w-full xl:w-auto flex items-center gap-2 justify-end">
                        <label htmlFor="items-per-page-select" className="text-sm font-medium text-brand-text-secondary-light dark:text-brand-text-secondary whitespace-nowrap">Show:</label>
                        <Select
                            id="items-per-page-select"
                            options={[
                                { value: 12, label: '12 per page' },
                                { value: 24, label: '24 per page' },
                                { value: 36, label: '36 per page' },
                                { value: 48, label: '48 per page' },
                            ]}
                            value={itemsPerPage}
                            onChange={(e) => setItemsPerPage(Number(e.target.value))}
                        />
                    </div>
                </div>
            </Card>

            {isLoadingClusters ? (
                <div className="text-center py-10"><Spinner className="w-8 h-8 mx-auto" /><p className="mt-2">Loading Clusters...</p></div>
            ) : filteredClusters.length > 0 ? (
                <>
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                        {paginatedClusters.map(cluster => (
                            <ClusterCard
                                key={cluster.id}
                                cluster={cluster}
                                onSelect={handleSelectCluster}
                                onViewed={handleClusterViewed}
                                hasBeenViewed={viewedClusters.has(cluster.id)}
                                isAdmin={isAdmin}
                                className="cluster-card-item"
                            />
                        ))}
                    </div>
                    <PaginationControls />
                </>
            ) : (
                <p className="text-center py-12 text-brand-text-secondary-light dark:text-brand-text-secondary">No clusters found matching your criteria.</p>
            )}

            {modalMode === 'details' && (
                <ClusterDetailModal 
                    cluster={selectedCluster} 
                    onClose={handleCloseModal} 
                    onEdit={handleEdit} 
                    onDelete={handleDelete}
                    showAdminControls={true} 
                />
            )}

            {modalMode === 'form' && (
                <AddEditClusterModal isOpen={modalMode === 'form'} onClose={handleCloseModal} clusterToEdit={clusterToEdit} />
            )}

            {clusterToDelete && (
                <Modal isOpen={!!clusterToDelete} onClose={() => setClusterToDelete(null)} title="Confirm Deletion" size="sm">
                    <p>Are you sure you want to delete the cluster "{clusterToDelete.name}"? This action cannot be undone.</p>
                    <div className="flex justify-end space-x-3 pt-6">
                        <Button variant="secondary" onClick={() => setClusterToDelete(null)} disabled={isDeleting}>Cancel</Button>
                        <Button variant="primary" className="bg-red-600 hover:bg-red-700 dark:bg-red-500 dark:hover:bg-red-600" onClick={confirmDelete} isLoading={isDeleting}>Delete</Button>
                    </div>
                </Modal>
            )}

            {canAddCluster && <BatchClusterUploadModal isOpen={isBatchUploadModalOpen} onClose={handleCloseBatchModal} />}
        </div>
        <InteractiveGuide steps={tourismClustersTourSteps} isOpen={isGuideActive} onClose={() => setIsGuideActive(false)} />
        </>
    );
};

