import { GoogleGenAI, Type } from "@google/genai";
import { AppEvent, Feedback } from '../types.ts';

// Helper to sleep for a given duration
const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Helper to get a formatted error message for AI operations
const getFormattedError = (err: unknown): string => {
    if (err instanceof Error) {
        const msg = err.message;

        // Handle specific Google Project Suspension
        if (msg.includes("CONSUMER_SUSPENDED") || msg.includes("has been suspended")) {
            return "CRITICAL: Your Google Cloud Project is suspended. To fix this: 1. Go to Google AI Studio. 2. Create a BRAND NEW Project. 3. Generate a new API key in that new project. Replacing the key in the current project will NOT work.";
        }

        if (msg.includes("403") || msg.includes("Permission denied") || msg.includes("API_KEY_INVALID")) {
            return `Access Denied: Please check if your API key is correct and has the 'Generative Language API' enabled. (Raw: ${msg})`;
        }

        if (msg.includes("429")) {
            return "The AI service is currently at its limit (Quota Exhausted). Please wait 60 seconds or try again. Switching to 'Flash' model to help avoid this.";
        }

        return msg;
    }
    return "An unexpected AI error occurred.";
};

/**
 * Wrapper to call AI with a single retry on 429 (Quota) errors.
 */
async function callAiWithRetry<T>(fn: () => Promise<T>, retries = 1): Promise<T> {
    try {
        return await fn();
    } catch (error: any) {
        if (retries > 0 && error?.message?.includes("429")) {
            // Wait 2 seconds and try one more time before failing
            await sleep(2000);
            return callAiWithRetry(fn, retries - 1);
        }
        throw error;
    }
}

/**
 * Summarizes system feedback for admins.
 */
export const summarizeFeedbackAI = async (feedbacks: Feedback[]): Promise<{ summary: string; sentiment: 'Positive' | 'Mixed' | 'Negative'; priorities: string[] }> => {
    if (feedbacks.length === 0) return { summary: "No feedback to analyze.", sentiment: 'Mixed', priorities: [] };

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    return callAiWithRetry(async () => {
        const feedbackText = feedbacks.map(f => `- ${f.content}`).join('\n');
        const prompt = `Analyze user feedback for the INTOURCAMS Sarawak Tourism system. Provide a summary, sentiment, and top 3 priorities.
        Feedback:
        ${feedbackText}`;

        const responseSchema = {
            type: Type.OBJECT,
            properties: {
                summary: { type: Type.STRING },
                sentiment: { type: Type.STRING, enum: ['Positive', 'Mixed', 'Negative'] },
                priorities: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["summary", "sentiment", "priorities"]
        };

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: responseSchema,
                thinkingConfig: { thinkingBudget: 0 }
            },
        });

        if (!response.text) throw new Error("Empty response from AI.");
        return JSON.parse(response.text);
    }).catch(error => {
        throw new Error(getFormattedError(error));
    });
};

