                            <Input label="Days" type="number" min="1" value={String(preferences.duration)} onChange={e => setPreferences(p => ({ ...p, duration: parseInt(e.target.value, 10) || 1 }))} />
                            <Input label="Budget (RM)" type="number" min="0" value={String(preferences.budget)} onChange={e => setPreferences(p => ({ ...p, budget: parseInt(e.target.value, 10) || 0 }))} />
                        </div>
                        <div>
                            <label className="block text-sm font-medium mb-2">Interests</label>
                            <div className="flex flex-wrap gap-2">
                                {activityOptions.map(activity => (
                                    <button
