                        <div id="get-recommendations-btn" className="flex justify-end">
                            <Button variant="primary" size="lg" onClick={handleGetRecommendations} isLoading={isLoading} leftIcon={<SparklesIcon className="w-5 h-5" />}>
                                Get Recommendations
