import { GoogleGenAI, Type } from "@google/genai";
import { AppEvent, Feedback } from '../types.ts';

// Helper to sleep for a given duration
const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Helper to get a formatted error message for AI operations
const getFormattedError = (err: unknown): string => {
    if (err instanceof Error) {
        const msg = err.message;

        // Handle specific Google Project Suspension
        if (msg.includes("CONSUMER_SUSPENDED") || msg.includes("has been suspended")) {
            return "CRITICAL: Your Google Cloud Project is suspended. To fix this: 1. Go to Google AI Studio. 2. Create a BRAND NEW Project. 3. Generate a new API key in that new project. Replacing the key in the current project will NOT work.";
        }

        if (msg.includes("403") || msg.includes("Permission denied") || msg.includes("API_KEY_INVALID")) {
            return `Access Denied: Please check if your API key is correct and has the 'Generative Language API' enabled. (Raw: ${msg})`;
        }

        if (msg.includes("429")) {
            return "The AI service is currently at its limit (Quota Exhausted). We are automatically retrying with backoff. If this persists, please wait 60 seconds.";
        }

        return msg;
    }
    return "An unexpected AI error occurred.";
};

/**
 * Wrapper to call AI with exponential backoff on 429 (Quota) errors.
 * Attempts: 3 | Delays: 2s, 4s, 8s
 */
async function callAiWithRetry<T>(fn: () => Promise<T>, attempts = 3, delay = 2000): Promise<T> {
    try {
        return await fn();
    } catch (error: any) {
        const isQuotaError = error?.message?.includes("429") || error?.status === 429;
        if (attempts > 1 && isQuotaError) {
            console.warn(`AI Quota hit. Retrying in ${delay}ms... (${attempts - 1} attempts left)`);
            await sleep(delay);
            return callAiWithRetry(fn, attempts - 1, delay * 2);
        }
        throw error;
    }
}

/**
 * Summarizes system feedback for admins.
 */
export const summarizeFeedbackAI = async (feedbacks: Feedback[]): Promise<{ summary: string; sentiment: 'Positive' | 'Mixed' | 'Negative'; priorities: string[] }> => {
    if (feedbacks.length === 0) return { summary: "No feedback to analyze.", sentiment: 'Mixed', priorities: [] };

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    return callAiWithRetry(async () => {
        const feedbackText = feedbacks.map(f => `- ${f.content}`).join('\n');
        const prompt = `Analyze user feedback for the INTOURCAMS Sarawak Tourism system. Provide a summary, sentiment, and top 3 priorities.
        Feedback:
        ${feedbackText}`;

        const responseSchema = {
            type: Type.OBJECT,
            properties: {
                summary: { type: Type.STRING },
                sentiment: { type: Type.STRING, enum: ['Positive', 'Mixed', 'Negative'] },
                priorities: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["summary", "sentiment", "priorities"]
        };

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: responseSchema,
                thinkingConfig: { thinkingBudget: 0 }
            },
        });

        if (!response.text) throw new Error("Empty response from AI.");
        return JSON.parse(response.text);
    }).catch(error => {
        throw new Error(getFormattedError(error));
    });
};

/**
 * Generates a marketing description for a tourism cluster.
 */
export const generateClusterDescription = async (name: string, categories: string[], vibe: string): Promise<string> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    return callAiWithRetry(async () => {
        const prompt = `Write a short, engaging description for a Sarawak tourism spot: "${name}" (${categories.join(', ')}). Tone: ${vibe || 'inviting'}. 2-3 sentences.`;
        const response = await ai.models.generateContent({ 
            model: 'gemini-3-flash-preview', 
            contents: prompt,
            config: { thinkingConfig: { thinkingBudget: 0 } }
        });
        return response.text?.trim() || "No description generated.";
    }).catch(error => {
        throw new Error(getFormattedError(error));
    });
};

/**
 * Generates an analytical summary for events.
 */
export const generateEventAnalyticsInsight = async (events: AppEvent[], year: number): Promise<{ summary: string; sources: any[] }> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    return callAiWithRetry(async () => {
        const titles = events.map(e => e.title).join(', ');
        const prompt = `Analyze Sarawak events for ${year}: ${titles}. Provide a strategic summary of trends.`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { 
                tools: [{ googleSearch: {} }]
            },
        });

        return { 
            summary: response.text || "No insights available.", 
            sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || [] 
        };
    }).catch(error => {
        throw new Error(getFormattedError(error));
    });
};

/**
 * Generates trip recommendations based on user preferences.
 */
export const generateItineraryRecommendations = async (preferences: any, items: any[]): Promise<any[]> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    return callAiWithRetry(async () => {
        // LIMIT: We only send max 15 items to keep the payload safe and small
        const minimalItems = items.slice(0, 15).map(item => ({
            id: item.id,
            type: item.itemType || item.type,
            name: item.name || item.title,
            location: item.display_address || item.location || item.location_name,
            categories: item.category ? (Array.isArray(item.category) ? item.category : [item.category]) : []
        }));

        const prompt = `Act as a Sarawak travel expert. Recommend exactly 5 items from the provided list for a ${preferences.duration}-day trip to ${preferences.location || 'Sarawak'} with interests in ${Array.from(preferences.activities).join(', ') || 'tourism'}.

        List of available spots:
        ${JSON.stringify(minimalItems)}`;

        const responseSchema = {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    id: { type: Type.STRING },
                    type: { type: Type.STRING },
                    name: { type: Type.STRING },
                    location: { type: Type.STRING },
                    justification: { type: Type.STRING }
                },
                required: ["id", "type", "name", "location", "justification"]
            }
        };

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview', // Flash has MUCH higher quota than Pro for free accounts
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: responseSchema,
                thinkingConfig: { thinkingBudget: 0 }
            },
        });

        return JSON.parse(response.text || "[]");
    }).catch(error => {
        throw new Error(getFormattedError(error));
    });
};

