        Events list: ${titles}`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { 
                tools: [{ googleSearch: {} }],
                thinkingConfig: { thinkingBudget: 0 } // Flash is enough for this, keep it fast
            },
        });

        return { 
            summary: response.text || "No insights available.", 
            sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || [] 
        };
    }).catch(error => {
        throw new Error(getFormattedError(error));
    });
};

/**
 * Generates trip recommendations based on user preferences.
 */
export const generateItineraryRecommendations = async (preferences: any, items: any[]): Promise<any[]> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    return callAiWithRetry(async () => {
        // LIMIT: We only send max 15 items to keep the payload safe and small
        const minimalItems = items.slice(0, 15).map(item => ({
            id: item.id,
            type: item.itemType || item.type,
            name: item.name || item.title,
            location: item.display_address || item.location || item.location_name,
            categories: item.category ? (Array.isArray(item.category) ? item.category : [item.category]) : []
        }));

        const prompt = `Act as a Sarawak travel expert. Recommend exactly 5 items from the provided list for a ${preferences.duration}-day trip to ${preferences.location || 'Sarawak'} with interests in ${Array.from(preferences.activities).join(', ') || 'tourism'}.

        List of available spots:
        ${JSON.stringify(minimalItems)}`;

        const responseSchema = {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    id: { type: Type.STRING },
                    type: { type: Type.STRING },
                    name: { type: Type.STRING },
                    location: { type: Type.STRING },
                    justification: { type: Type.STRING }
                },
                required: ["id", "type", "name", "location", "justification"]
            }
        };

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview', // Flash has MUCH higher quota than Pro for free accounts
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: responseSchema,
                thinkingConfig: { thinkingBudget: 0 }
            },
        });

        return JSON.parse(response.text || "[]");
    }).catch(error => {
        throw new Error(getFormattedError(error));
    });
};

