                        </div>
                    )}
                </Card>

                <Card title="AI Strategic Insights" className="lg:col-span-2" actions={
                    isAdminOrEditor && filteredEvents.length > 0 && (
                        <Button 
                            variant="ghost" 
                            size="sm" 
                            onClick={() => loadSummary(true)} 
                            isLoading={isGeneratingSummary} 
                            disabled={cooldown > 0}
                            leftIcon={cooldown > 0 ? <ClockIcon className="w-4 h-4"/> : <RefreshIcon className="w-4 h-4"/>}
                        >
                            {cooldown > 0 ? `Wait ${cooldown}s` : (aiInsight ? 'Refresh' : 'Generate')}
