                                <div className="text-xs text-red-800 dark:text-red-300">
                                    <p className="font-bold">Service Temporarily Busy</p>
                                    <p className="mt-1">{error}</p>
                                    {error.includes('Quota') && (
                                        <p className="mt-2 font-semibold">Please wait for the cooldown timer (top right) to expire.</p>
