                    ) : (
                        <div className="space-y-4 text-sm leading-relaxed">
                            {aiInsight ? (
                                <>
                                    <div className="prose prose-sm dark:prose-invert">
                                        <p className="text-brand-text-light dark:text-brand-text">{aiInsight.summary}</p>
