import { GoogleGenAI, Type } from "@google/genai";
import { AppEvent, Feedback } from '../types.ts';

// Helper to sleep for a given duration
const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Helper to get a formatted error message for AI operations
const getFormattedError = (err: unknown): string => {
    if (err instanceof Error) {
        const msg = err.message;

        if (msg.includes("CONSUMER_SUSPENDED") || msg.includes("has been suspended")) {
            return "CRITICAL: Your Google Cloud Project is suspended. Please create a new API key in a fresh project at Google AI Studio.";
        }

        if (msg.includes("403") || msg.includes("Permission denied") || msg.includes("API_KEY_INVALID")) {
            return `Access Denied: Check API key configuration.`;
        }

        if (msg.includes("429")) {
            return "Quota Limit Hit: The system is performing high-depth research. Please wait for the cooldown timer (30s) to allow the API to reset.";
        }

        return msg;
    }
    return "An unexpected AI error occurred.";
};

/**
 * Wrapper to call AI with exponential backoff on 429 (Quota) errors.
 */
async function callAiWithRetry<T>(fn: () => Promise<T>, attempts = 3, delay = 4000): Promise<T> {
    try {
        return await fn();
    } catch (error: any) {
        const isQuotaError = error?.message?.includes("429") || error?.status === 429;
        if (attempts > 1 && isQuotaError) {
            console.warn(`Quota limit reached. Retrying research in ${delay}ms...`);
            await sleep(delay);
            return callAiWithRetry(fn, attempts - 1, delay * 2);
        }
        throw error;
    }
}

/**
 * Summarizes system feedback for admins.
 */
export const summarizeFeedbackAI = async (feedbacks: Feedback[]): Promise<{ summary: string; sentiment: 'Positive' | 'Mixed' | 'Negative'; priorities: string[] }> => {
    if (feedbacks.length === 0) return { summary: "No feedback to analyze.", sentiment: 'Mixed', priorities: [] };

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    return callAiWithRetry(async () => {
        const feedbackText = feedbacks.map(f => `- ${f.content}`).join('\n');
        const prompt = `Analyze Sarawak Tourism system feedback. 
        Feedback:
        ${feedbackText}`;

        const responseSchema = {
            type: Type.OBJECT,
            properties: {
                summary: { type: Type.STRING },
                sentiment: { type: Type.STRING, enum: ['Positive', 'Mixed', 'Negative'] },
                priorities: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["summary", "sentiment", "priorities"]
        };

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: responseSchema,
                thinkingConfig: { thinkingBudget: 0 }
            },
        });

        if (!response.text) throw new Error("Empty response from AI.");
        return JSON.parse(response.text);
    });
};

/**
 * Generates a marketing description for a tourism cluster.
 */
export const generateClusterDescription = async (name: string, categories: string[], vibe: string): Promise<string> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    return callAiWithRetry(async () => {
        const prompt = `Write a short, engaging description for Sarawak tourism spot: "${name}" (${categories.join(', ')}). Tone: ${vibe || 'inviting'}. 2 sentences.`;
        const response = await ai.models.generateContent({ 
            model: 'gemini-3-flash-preview', 
            contents: prompt,
            config: { thinkingConfig: { thinkingBudget: 0 } }
        });
        return response.text?.trim() || "No description generated.";
    });
};

/**
 * Generates a comprehensive analytical summary for events.
 * restored grounding but uses optimized semantic compression.
 */
export const generateEventAnalyticsInsight = async (context: string, year: number): Promise<{ summary: string; sources: any[] }> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    return callAiWithRetry(async () => {
        const prompt = `You are a Sarawak Tourism Strategist. Analyze the following data for ${year}:
        ${context}

        Instructions:
        1. Use Google Search to correlate these events with regional/global tourism trends.
        2. Identify key opportunities for growth.
        3. Provide a 2-paragraph high-impact summary. 
        4. Reference specific events from the data provided if relevant.`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { 
                tools: [{ googleSearch: {} }],
                thinkingConfig: { thinkingBudget: 0 } 
            },
        });

        return { 
            summary: response.text || "No insights available.", 
            sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || [] 
        };
    }).catch(error => {
        throw new Error(getFormattedError(error));
    });
};

/**
 * Generates trip recommendations based on user preferences.
 */
export const generateItineraryRecommendations = async (preferences: any, items: any[]): Promise<any[]> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    return callAiWithRetry(async () => {
        const minimalItems = items.slice(0, 15).map(item => ({
            id: item.id,
            type: item.itemType || item.type,
            name: item.name || item.title,
            location: item.display_address || item.location || item.location_name,
            categories: item.category ? (Array.isArray(item.category) ? item.category : [item.category]) : []
        }));

        const prompt = `Recommend exactly 5 Sarawak spots for a ${preferences.duration}-day trip to ${preferences.location || 'Sarawak'} interested in ${Array.from(preferences.activities).join(', ') || 'tourism'}.
        Spots: ${JSON.stringify(minimalItems)}`;

        const responseSchema = {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    id: { type: Type.STRING },
                    type: { type: Type.STRING },
                    name: { type: Type.STRING },
                    location: { type: Type.STRING },
                    justification: { type: Type.STRING }
                },
                required: ["id", "type", "name", "location", "justification"]
            }
        };

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: responseSchema,
                thinkingConfig: { thinkingBudget: 0 }
            },
        });

        return JSON.parse(response.text || "[]");
    });
};

