                    .join('\n');

                const richContext = `
                TOTAL EVENTS: ${filteredEvents.length}
                MONTHLY BREAKDOWN: ${monthDistribution}
                CATEGORY BREAKDOWN: ${categoriesStr}

                KEY REPRESENTATIVE EVENTS:
                ${significantEvents}`;

                const insight = await generateEventAnalyticsInsight(richContext, selectedYear);
                setAiInsight(insight);
                const timestamp = await getLatestEventTimestampForYear(selectedYear);
                await setCachedAiInsight('event_analytics', cacheKey, JSON.stringify(insight), timestamp || new Date().toISOString());
            } else {
                const cached = await getCachedAiInsight('event_analytics', cacheKey);
                if (cached) setAiInsight(JSON.parse(cached.content));
                else setAiInsight(null);
            }
