                                    <YAxis stroke={chartColors.axis} allowDecimals={false} />
                                    <Tooltip contentStyle={{ backgroundColor: chartColors.tooltipBg }} cursor={{ fill: 'rgba(0,0,0,0.1)' }} />
                                    <Bar dataKey="Number of Events" fill={chartColors.bar} radius={[4, 4, 0, 0]} />
