            return "The AI system is resting to reset its free-tier quota. Deep research with Google Search requires more resources. Please wait for the 60s timer.";
        }

        return msg;
    }
    return "An unexpected AI error occurred.";
};

/**
 * Wrapper to call AI with aggressive exponential backoff on 429 (Quota) errors.
 * Attempts: 3 | Initial Delay: 5s (Better for free tier reset)
 */
async function callAiWithRetry<T>(fn: () => Promise<T>, attempts = 3, delay = 5000): Promise<T> {
    try {
        return await fn();
    } catch (error: any) {
        const isQuotaError = error?.message?.includes("429") || error?.status === 429;
        if (attempts > 1 && isQuotaError) {
            console.warn(`Quota limit reached. Resting for ${delay}ms...`);
            await sleep(delay);
            return callAiWithRetry(fn, attempts - 1, delay * 2);
        }
        throw error;
    }
}

