// Helper to sleep for a given duration
const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Helper to get a formatted error message for AI operations
const getFormattedError = (err: unknown): string => {
    if (err instanceof Error) {
        const msg = err.message;

        if (msg.includes("CONSUMER_SUSPENDED") || msg.includes("has been suspended")) {
            return "CRITICAL: Your Google Cloud Project is suspended. Please generate a new API key in a fresh project at Google AI Studio.";
        }

        if (msg.includes("403") || msg.includes("Permission denied") || msg.includes("API_KEY_INVALID")) {
            return `Access Denied: Please check your API key configuration.`;
        }

        if (msg.includes("429")) {
            return "Quota Limit Hit: Web-grounded research is resource-intensive on the free tier. Please wait 60s for the system to reset.";
        }

        return msg;
    }
    return "An unexpected AI error occurred.";
};

/**
 * Wrapper to call AI with aggressive exponential backoff on 429 (Quota) errors.
 */
async function callAiWithRetry<T>(fn: () => Promise<T>, attempts = 3, delay = 5000): Promise<T> {
    try {
        return await fn();
    } catch (error: any) {
        const isQuotaError = error?.message?.includes("429") || error?.status === 429;
        if (attempts > 1 && isQuotaError) {
            console.warn(`Quota reached. Resting for ${delay}ms...`);
            await sleep(delay);
            return callAiWithRetry(fn, attempts - 1, delay * 2);
        }
        throw error;
    }
}

