         try {
            const filePath = new URL(fileUrl).pathname.split(`/${bucket}/`)[1];
            if(filePath) {
                const { error } = await supabase.storage.from(bucket).remove([filePath]);
                if (error) throw error;
            }
        } catch (e) {
            console.error(`Error deleting file from ${bucket}:`, e);
            throw e;
        }
    },
