    // --- AI Caching ---
    async getCachedAiInsight(viewName: string, filterKey: string) {
        const { data, error } = await supabaseClient.from('ai_insights').select('content, previous_content, data_last_updated_at').eq('view_name', viewName).eq('filter_key', filterKey).single();
        if (error && error.code !== 'PGRST116') throw error; 
        return data;
    },
    async setCachedAiInsight(viewName: string, filterKey: string, content: string, dataLastUpdatedAt: string) {
        // Atomic versioning: Move existing content to previous_content before updating
        const existing = await this.getCachedAiInsight(viewName, filterKey);

        const { error } = await (supabaseClient.from('ai_insights') as any).upsert(
            { 
                view_name: viewName, 
                filter_key: filterKey, 
                content, 
                previous_content: existing?.content || null,
                data_last_updated_at: dataLastUpdatedAt 
            },
            { onConflict: 'view_name,filter_key' }
        );
        if (error) throw error;
    },
    async getLatestEventTimestampForYear(year: number) {
        const startDate = `${year}-01-01T00:00:00.000Z`;
        const endDate = `${year}-12-31T23:59:59.999Z`;
        const { data, error } = await supabaseClient.from('events').select('updated_at').gte('start_date', startDate).lte('start_date', endDate).order('updated_at', { ascending: false }).limit(1).single();
        if (error && error.code !== 'PGRST116') throw error;
        return data ? (data as any).updated_at : null;
    },

