        if (data) return data.id;

        const { data: newData, error: insertError }: { data: Tables<'itineraries'> | null; error: PostgrestError | null } = await (supabaseClient
            .from('itineraries') as any)
            .insert({ user_id: userId, name: "My Itinerary" })
            .select()
