const dashboardTourSteps = [
    { selector: '#hero-welcome-text', title: 'Welcome to INTOURCAMS', content: 'This is your primary hub for monitoring and coordinating Sarawak tourism activities.' },
    { selector: '#global-search-form', title: 'Global Search', content: 'Quickly find any Cluster, Event, or Grant application by name, category, or ID.' },
