            setCurrentView(ViewName.GrantApplications);
        }
    }
    setIsSearchResultsModalOpen(false);
  };

  const formatLargeNumber = (num: number) => {
      if (num >= 1000000) return `${(num / 1000000).toFixed(1)}M`;
      if (num >= 1000) return `${(num / 1000).toFixed(1)}K`;
      return num.toString();
  };

  return (
    <>
